impl BootstrapReposStatus {
    async fn run(self) -> Result<()> {
        let config = Config::get().await?;
        let repos = system::repos_from_config(&config);
        let mut any_missing = false;
        let mut rows: Vec<Vec<String>> = vec![];
        let mut json_entries = vec![];
        for s in system::repos::status(&repos)? {
            if !s.state.is_current() {
                any_missing = true;
            }
            let state = s.state.as_str();
            let reason = match &s.state {
                RepoState::Conflict(reason) => reason.clone(),
                RepoState::Dirty => "local changes".to_string(),
                RepoState::Current | RepoState::Missing | RepoState::Differs => "".to_string(),
            };
            if self.json {
                json_entries.push(json!({
                    "path": s.request.path,
                    "path_raw": s.request.path_raw,
                    "url": s.request.url,
                    "ref": s.request.git_ref,
                    "origin": s.origin,
                    "current_ref": s.current_ref,
                    "current_sha": s.current_sha,
                    "state": state,
                    "reason": reason,
                }));
            } else {
                rows.push(vec![
                    s.request.path_raw,
                    s.request.url,
                    s.request.git_ref.unwrap_or_default(),
                    state.to_string(),
                    reason,
                ]);
            }
        }
        if self.json {
            let mut json_out = serde_json::Map::new();
            json_out.insert("repos".to_string(), json!(json_entries));
            miseprintln!("{}", serde_json::to_string_pretty(&json_out)?);
        } else if rows.is_empty() {
            info!("nothing configured in [bootstrap.repos]");
        } else {
            info!("login_shell: set to {}", request.shell);
        }
    }
    Ok(BootstrapApplyReport {
        needs_follow_up,
        skipped_reason: None,
    })
}

/// Apply `[bootstrap.mise_shell_activate]` entries using dotfile edit blocks.
pub(crate) fn apply_shell_activation(
    config: &Config,
    requests: Vec<system::shell_activation::ShellActivationRequest>,
    dry_run: bool,
    yes: bool,
) -> Result<()> {
    if requests.is_empty() {
        return Ok(());
    }
    let edits = requests
        .into_iter()
        .map(|request| request.edit)
        .collect::<Vec<_>>();
    let opts = system::edits::ApplyOpts {
        dry_run,
        verbose: Settings::get().verbose,
        yes,
    };
    system::edits::apply(config, &edits, &opts)
}

/// Apply `[bootstrap.repos]` entries that are missing or differ.
pub(crate) fn apply_repos(
    repos: Vec<system::repos::RepoRequest>,
    dry_run: bool,
    yes: bool,
) -> Result<()> {
    use crate::system::repos;
    if repos.is_empty() {
